; CHECK-SAME: float nofpclass(inf sub norm) [[ZERO_OR_NAN:%.*]], float nofpclass(inf) [[NOT_INF:%.*]]) {
; CHECK-NEXT:    [[MUL:%.*]] = fmul ninf float [[ZERO_OR_NAN]], [[NOT_INF]]
; CHECK-NEXT:    ret float [[MUL]]
  %mul = fmul float %zero.or.nan, %not.inf
  ret float %mul
}

